/* ===== CPU Lifecycle ===== */
CPUState *simple8_create(size_t memory_size) {
    CPUState *cpu = (CPUState *)calloc(1, sizeof(CPUState));
    if (!cpu) return NULL;
    
    cpu->memory = (uint8_t *)calloc(1, memory_size);
    if (!cpu->memory) {
        free(cpu);
        return NULL;
    }
    cpu->memory_size = memory_size;
    
    /* Initialize port memory */
    cpu->port_size = 256;
    cpu->port_memory = (uint8_t *)calloc(1, cpu->port_size);
    
    /* Initialize hooks */
    for (int i = 0; i < (int)HOOK_COUNT; i++) {
        cpu->hooks[i].enabled = false;
        cpu->hooks[i].func = NULL;
        cpu->hooks[i].context = NULL;
    }
    
    simple8_reset(cpu);
    return cpu;
}

void simple8_destroy(CPUState *cpu) {
    if (cpu) {
        free(cpu->memory);
        free(cpu->port_memory);
        free(cpu);
    }
}

void simple8_reset(CPUState *cpu) {
    memset(cpu->registers, 0, sizeof(cpu->registers));
    cpu->pc = 0;
    cpu->sp = 0;
    cpu->flags.raw = 0;
    /* No shadow flag bank */
    /* Interrupt model: none */
    cpu->running = true;
    cpu->halted = false;
    cpu->error_code = CPU_ERROR_NONE;
    cpu->total_cycles = 0;
    cpu->pc_modified = false;
    cpu->hook_pc = 0;
    cpu->hook_prefix = 0;
    cpu->hook_opcode = 0;
    cpu->hook_raw = 0;
    cpu->tracing_enabled = false;
    cpu->num_break_points = 0;
}

int simple8_load_rom(CPUState *cpu, const char *filename, uint16_t address) {
    FILE *f = fopen(filename, "rb");
    if (!f) return -1;
    
    fseek(f, 0, SEEK_END);
    long size = ftell(f);
    fseek(f, 0, SEEK_SET);
    
    if (address + size > cpu->memory_size) {
        fclose(f);
        return -1;
    }
    
    fread(&cpu->memory[address], 1, size, f);
    fclose(f);
    return 0;
}

/* ===== Memory Access ===== */
uint8_t simple8_read_byte(CPUState *cpu, uint16_t addr) {
    if (addr >= cpu->memory_size) {
        cpu->error_code = CPU_ERROR_INVALID_MEMORY;
        return 0xFF;
    }
    return cpu->memory[addr];
}

void simple8_write_byte(CPUState *cpu, uint16_t addr, uint8_t value) {
    if (addr >= cpu->memory_size) {
        cpu->error_code = CPU_ERROR_INVALID_MEMORY;
        return;
    }

    cpu->memory[addr] = value;
}

uint16_t simple8_read_word(CPUState *cpu, uint16_t addr) {
    uint16_t lo = simple8_read_byte(cpu, addr);
    uint16_t hi = simple8_read_byte(cpu, addr + 1);
    return lo | (hi << 8);
}

void simple8_write_word(CPUState *cpu, uint16_t addr, uint16_t value) {
    simple8_write_byte(cpu, addr, value & 0xFF);
    simple8_write_byte(cpu, addr + 1, (value >> 8) & 0xFF);
}

/* ===== Port I/O ===== */
uint8_t simple8_read_port(CPUState *cpu, uint8_t port) {

    if (port >= cpu->port_size) return 0xFF;
    uint8_t value = cpu->port_memory[port];

    return value;
}

void simple8_write_port(CPUState *cpu, uint8_t port, uint8_t value) {

    if (port >= cpu->port_size) return;
    cpu->port_memory[port] = value;

}

